#include<bits/stdc++.h>
using namespace std;
unsigned int nxt[15010],pos[15010],a[15010];
unsigned int read()
{
    unsigned int x=0;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=(x<<3)+(x<<1)+(ch-'0');
        ch=getchar();
    }
    return x;
}
int main()
{
    unsigned int t;
    scanf("%u",&t);
    while(t--)
    {
        unsigned int n=read();
        for(unsigned int i=1;i<=n;i++)
        {
            a[i]=read();
        }
        memset(nxt,0,sizeof(nxt));
        memset(pos,0,sizeof(pos));
        for(unsigned int i=n;i>=1;i--)
        {
            nxt[i]=pos[a[i]];
            pos[a[i]]=i;
        }
        unsigned int q=read();
        while(q--)
        {
            unsigned int l=read(),r=read();
            unsigned int cnt=0;
            for(unsigned int j=l;j<=r;j++)
            {
                if(nxt[j]&&nxt[j]<=r)
                {
                    j=nxt[j];
                }
                else
                {
                    cnt++;
                }
            }
            printf("%u\n",cnt);
        }
    }
    return 0;
}
